namespace sv_86dea21ef5ae433b8e16ddd790e16203.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped service that holds the currently selected warehouse for a single user circuit.
/// Components subscribe to OnChange to react when the selection changes.
/// </summary>
public class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "WH-A", Name = "Warehouse A" },
        new() { Id = "WH-B", Name = "Warehouse B" },
        new() { Id = "WH-C", Name = "Warehouse C" },
    ];

    public WarehouseInfo Current { get; private set; } = AvailableWarehouses[0];

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        var warehouse = AvailableWarehouses.FirstOrDefault(w => w.Id == warehouseId);
        if (warehouse is null || warehouse.Id == Current.Id) return;

        Current = warehouse;
        OnChange?.Invoke();
    }
}

namespace sv_86dea21ef5ae433b8e16ddd790e16203.Services;

/// <summary>
/// Scoped service that tracks low-stock alert counts per warehouse.
/// Supports polling with change notification so all subscribed components update together.
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;

    public int CurrentAlertCount { get; private set; }
    public event Action? OnAlertCountChanged;

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulates a database query — returns a random number between 0 and 15.
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Starts polling every 10 seconds for the given warehouse.
    /// Reference-counted: multiple callers share one timer.
    /// </summary>
    public void StartPolling(Func<string> getWarehouseId)
    {
        _subscriberCount++;
        if (_subscriberCount > 1) return; // already running

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));

        _ = PollLoopAsync(getWarehouseId, _cts.Token);
    }

    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount > 0) return; // other subscribers still active

        _cts?.Cancel();
        _timer?.Dispose();
        _cts?.Dispose();
        _timer = null;
        _cts = null;
    }

    /// <summary>
    /// Fetches fresh data and notifies all subscribers. Can be called on-demand
    /// (e.g. when the warehouse changes) in addition to the timed poll.
    /// </summary>
    public async Task RefreshAsync(string warehouseId)
    {
        CurrentAlertCount = await GetLowStockCountAsync(warehouseId);
        OnAlertCountChanged?.Invoke();
    }

    private async Task PollLoopAsync(Func<string> getWarehouseId, CancellationToken ct)
    {
        // Fetch immediately on start so subscribers don't wait 10 seconds.
        await RefreshAsync(getWarehouseId());

        while (!ct.IsCancellationRequested)
        {
            try
            {
                if (!await _timer!.WaitForNextTickAsync(ct)) break;
                await RefreshAsync(getWarehouseId());
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _timer?.Dispose();
        _cts?.Dispose();
    }
}

