arguments.file_text:
@page "/dashboard"
@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@using sv_86dea21ef5ae433b8e16ddd790e16203.Services
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">Current Warehouse: @WarehouseState.Current.Name</h5>
        <p class="card-text">Site ID: @WarehouseState.Current.Id</p>
    </div>
</div>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">
            Low-Stock Alerts
            @if (AlertService.CurrentAlertCount > 0)
            {
                <span class="badge bg-danger ms-2">@AlertService.CurrentAlertCount items</span>
            }
            else
            {
                <span class="badge bg-success ms-2">All stocked</span>
            }
        </h5>
        <p class="text-muted">Refreshes every 10 seconds while this page is open.</p>
    </div>
</div>

@code {
    private Action? _warehouseHandler;
    private Action? _alertHandler;

    protected override void OnInitialized()
    {
        _warehouseHandler = async () =>
        {
            // Warehouse changed — fetch fresh alerts for the new site immediately.
            await AlertService.RefreshAsync(WarehouseState.Current.Id);
            await InvokeAsync(StateHasChanged);
        };
        WarehouseState.OnChange += _warehouseHandler;

        _alertHandler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertCountChanged += _alertHandler;

        // Start polling; the lambda captures the live warehouse selection.
        AlertService.StartPolling(() => WarehouseState.Current.Id);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= _warehouseHandler;
        AlertService.OnAlertCountChanged -= _alertHandler;
        AlertService.StopPolling();
    }
}

